grid:







      onchange="onChange$GridVoucherDetail$Employee(this);"














































































        select 'this._voucherCode='@@id';load$GridVoucherDetail$(this);' as message
return




        select 'dispose$GridVoucherDetail$(this);' as message
return







/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    tn_ct: '[tn_ct]:=[tn_ct_nt]*[$ty_gia]',
    tien_gt: '[tien_gt]:=[tien_gt_nt]*[$ty_gia]',
    tn_tt: '[tn_tt]:=([tinh_thue_yn] ? ([tn_ct] > [tien_gt] ? [tn_ct] - [tien_gt] : 0) : 0)',
    tn_tt_nt: '[tn_tt_nt]:=([tinh_thue_yn] ? ([tn_ct_nt] > [tien_gt_nt] ? [tn_ct_nt] - [tien_gt_nt] : 0) : 0)',
    tn_tt_tg: '[tn_tt]:=[tn_tt_nt]*[$ty_gia]',
    thue: '[thue]:=[tn_tt]*[$thue_suat]/100',
    thue_tg: '[thue]:=[thue_nt]*[$ty_gia]',
    thue_nt: '[thue_nt]:=[tn_tt_nt]*[$thue_suat]/100',

    t_tn_ct_nt: ['t_tn_ct_nt', 'tn_ct_nt'],
    t_tn_ct: ['t_tn_ct', 'tn_ct'],
    t_tien_gt_nt: ['t_tien_gt_nt', 'tien_gt_nt'],
    t_tien_gt: ['t_tien_gt', 'tien_gt'],
    t_tn_tt_nt: ['t_tn_tt_nt', 'tn_tt_nt'],
    t_tn_tt: ['t_tn_tt', 'tn_tt'],
    t_thue_nt: ['t_thue_nt', 'thue_nt'],
    t_thue: ['t_thue', 'thue'],
  };
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Employee(o) {o.grid.request(o, 'Employee', 'Employee', ['ma_ns']);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'tn_ct_nt':
      g.validExpression(o, [g.$a.tn_ct, g.$a.tn_tt_nt, g.$a.tn_tt_tg, g.$a.thue_nt, g.$a.thue], [g.$a.t_tn_ct_nt, g.$a.t_tn_ct, g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue]);
      break;
    case 'tien_gt_nt':
      g.validExpression(o, [g.$a.tien_gt, g.$a.tn_tt_nt, g.$a.tn_tt_tg, g.$a.thue_nt, g.$a.thue], [g.$a.t_tien_gt_nt, g.$a.t_tien_gt, g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue], null, 'tn_tt_nt');
      break;
    case 'tn_tt_nt':
      g.validExpression(o, [g.$a.tn_tt_tg, g.$a.thue_nt, g.$a.thue], [g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue], null, 'thue_nt');
      break;
    case 'thue_nt':
      g.validExpression(o, [g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue]);
      break;
    case 'tn_ct':
      g.validExpression(o, [g.$a.tn_tt, g.$a.thue], [g.$a.t_tn_ct, g.$a.t_tn_tt, g.$a.t_thue]);
      break;
    case 'tien_gt':
      g.validExpression(o, [g.$a.tn_tt, g.$a.thue], [g.$a.t_tien_gt, g.$a.t_tn_tt, g.$a.t_thue], null, 'tn_tt');
      break;
    case 'tn_tt':
      g.validExpression(o, [g.$a.thue], [g.$a.t_tn_tt, g.$a.t_thue], [g.$a.t_tn_tt, g.$a.t_thue], null, 'thue');
      break;
    case 'thue':
      g.executeAggregate([g.$a.t_thue]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Employee':
      var v = (f.getItemValue('ma_nt') == f._baseCurrency), l0 = g._getColumnOrder('tien_gt'), l1 = g._getColumnOrder('tien_gt_nt'), l2 = g._getColumnOrder('tinh_thue_yn'), r = g._activeRow;
      if (f._baseCurrencyAmount) {
        if (g._getItemValue(r, l0) == 0) {
          g._setItemValue(r, l0, f._baseCurrencyAmount);
          g.executeAggregate([g.$a.t_tien_gt]);
        }
        if (g._getItemValue(r, l1) == 0) {
          g._setItemValue(r, l1, v ? f._baseCurrencyAmount : f._foreignCurrencyAmount);
          g.executeAggregate([g.$a.t_tien_gt_nt]);
        }
      }

      if (g._getItemValue(r, l2) != result[0].Value) {
        g.setItemGridBehavior(o, [['tinh_thue_yn', result[0].Value, '', true]]);
        g.executeExpression(o, [g.$a.tn_tt_nt, g.$a.tn_tt, g.$a.thue_nt, g.$a.thue], [g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue]);
      }
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_tn_ct_nt, g.$a.t_tn_ct, g.$a.t_tien_gt_nt, g.$a.t_tien_gt, g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue]);}
/* </flatten> */








if exists(select 1 from phns where ma_ns = @ma_ns and status = '1') begin
  select tinh_thue_yn as tinh_thue_yn from phns where ma_ns = @ma_ns
  return
end









